namespace sv_217291bb0f0f47bdbf475b8931f1fe55.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

namespace sv_217291bb0f0f47bdbf475b8931f1fe55.Services;

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Spaghetti Carbonara", "Classic Roman pasta with eggs, pecorino, guanciale, and black pepper.", 25),
            new(2, "Margherita Pizza", "Neapolitan pizza with San Marzano tomatoes, mozzarella, and fresh basil.", 45),
            new(3, "Tiramisu", "Layered dessert with espresso-soaked ladyfingers and mascarpone cream.", 30),
        },
        [2] = new List<Recipe>
        {
            new(4, "Pad Thai", "Stir-fried rice noodles with shrimp, tofu, peanuts, and tamarind sauce.", 20),
            new(5, "Green Curry", "Aromatic coconut curry with Thai basil, bamboo shoots, and chicken.", 35),
            new(6, "Tom Yum Soup", "Hot and sour soup with lemongrass, galangal, and prawns.", 15),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Marinated pork tacos with pineapple, cilantro, and onion.", 40),
            new(8, "Guacamole", "Fresh avocado dip with lime, cilantro, jalapeño, and tomato.", 10),
            new(9, "Chicken Enchiladas", "Corn tortillas filled with chicken, smothered in red sauce and cheese.", 50),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@implements IDisposable
@inject IRecipeService RecipeService
@inject NavigationManager Navigation
@inject ILogger<Recipes> Logger

<PageTitle>Recipes</PageTitle>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p class="text-muted"><small>Refreshing…</small></p>
    }

    <h3>Recipes</h3>
    @if (_displayedRecipes.Count == 0)
    {
        <p>No recipes found for this cuisine.</p>
    }
    else
    {
        <ul>
            @foreach (var recipe in _displayedRecipes)
            {
                <li>
                    <strong>@recipe.Title</strong> — @recipe.Description
                    <br /><em>Prep time: @recipe.PrepTimeMinutes min</em>
                </li>
            }
        </ul>
    }
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private List<Recipe> _displayedRecipes = new();
    private bool _isRefreshing;
    private string? _error;

    private int _loadedCuisineId;
    private CancellationTokenSource? _loadCts;
    private readonly CancellationTokenSource _disposeCts = new();

    protected override Task OnParametersSetAsync()
    {
        if (CuisineId != _loadedCuisineId)
        {
            return LoadRecipesAsync();
        }

        ApplySort();
        return Task.CompletedTask;
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight load
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
        }

        _loadCts = CancellationTokenSource.CreateLinkedTokenSource(_disposeCts.Token);
        var cts = _loadCts;
        var cuisineId = CuisineId;

        _error = null;
        _isRefreshing = _recipes is not null;

        try
        {
            var result = await RecipeService.GetByCuisineAsync(cuisineId, cts.Token);

            if (cts.Token.IsCancellationRequested)
                return;

            _recipes = result;
            _loadedCuisineId = cuisineId;
            _isRefreshing = false;
            ApplySort();
        }
        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested)
        {
            // Expected when user navigates away or switches cuisine; do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", cuisineId);
            _isRefreshing = false;
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", cuisineId);
            _isRefreshing = false;
            _error = "Something went wrong loading recipes. Please try again.";
        }
    }

    private Task RetryAsync() => LoadRecipesAsync();

    private void ApplySort()
    {
        if (_recipes is null)
            return;

        _displayedRecipes = Sort?.ToLowerInvariant() switch
        {
            "newest" => _recipes.OrderByDescending(r => r.Id).ToList(),
            "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes).ToList(),
            _ => _recipes.ToList(),
        };
    }

    public void Dispose()
    {
        _disposeCts.Cancel();
        _disposeCts.Dispose();
        _loadCts?.Dispose();
    }
}

